    mathSolution: "people.GroupBy(p => p.City)",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Employee\n{\n    public string Name { get; set; }\n    public string Department { get; set; }\n    public decimal Salary { get; set; }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<Employee> employees = new List<Employee>\n        {\n            new Employee { Name = \"Alice\", Department = \"IT\", Salary = 60000 },\n            new Employee { Name = \"Bob\", Department = \"HR\", Salary = 50000 },\n            new Employee { Name = \"Charlie\", Department = \"IT\", Salary = 65000 },\n            new Employee { Name = \"Diana\", Department = \"HR\", Salary = 52000 },\n            new Employee { Name = \"Eve\", Department = \"Sales\", Salary = 55000 }\n        };\n        \n        var byDept = employees.GroupBy(e => e.Department);\n        \n        foreach (var group in byDept)\n        {\n            Console.WriteLine($\"Department: {group.Key}\");\n            foreach (var emp in group)\n                Console.WriteLine($\"  {emp.Name}: ${emp.Salary}\");\n            Console.WriteLine($\"  Average salary: ${group.Average(e => e.Salary):F2}\");\n            Console.WriteLine();\n        }\n    }\n}",
    hint: "GroupBy lambda specifies the grouping key.",
