    question: "Use lambda with Zip for three sequences.",
    mathSolution: "numbers1.Zip(numbers2, (a, b) => a + b).Zip(numbers3, (ab, c) => ab + c)",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers1 = { 1, 2, 3, 4 };\n        int[] numbers2 = { 10, 20, 30, 40 };\n        int[] numbers3 = { 100, 200, 300, 400 };\n        \n        // Zip three sequences\n        var result = numbers1.Zip(numbers2, (a, b) => a + b)\n                            .Zip(numbers3, (ab, c) => ab + c);\n        Console.WriteLine($\"Sum of three: {string.Join(\", \", result)}\");\n        \n        // Zip with different lengths (stops at shortest)\n        int[] shortList = { 1, 2 };\n        int[] longList = { 10, 20, 30, 40 };\n        var zipped = shortList.Zip(longList, (a, b) => $\"{a}+{b}={a + b}\");\n        foreach (var item in zipped)\n            Console.WriteLine(item);\n    }\n}",
    hint: "Zip stops when the shortest sequence ends.",
