    question: "Use lambda with DefaultIfEmpty for handling empty collections.",
    mathSolution: "list.DefaultIfEmpty(0)",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        List<int> empty = new List<int>();\n        List<int> nonEmpty = new List<int> { 1, 2, 3 };\n        \n        var withDefault = empty.DefaultIfEmpty();\n        Console.WriteLine($\"Empty with default: {string.Join(\", \", withDefault)}\");\n        \n        var withCustomDefault = empty.DefaultIfEmpty(99);\n        Console.WriteLine($\"Empty with custom default: {string.Join(\", \", withCustomDefault)}\");\n        \n        var nonEmptyWithDefault = nonEmpty.DefaultIfEmpty(0);\n        Console.WriteLine($\"Non-empty with default: {string.Join(\", \", nonEmptyWithDefault)}\");\n        \n        // Practical use: Left join simulation\n        List<int> left = new List<int> { 1, 2, 3 };\n        List<int> right = new List<int> { 1, 3 };\n        \n        var leftJoin = left.GroupJoin(right,\n            l => l,\n            r => r,\n            (l, r) => new { Left = l, Right = r.DefaultIfEmpty(-1) });\n        \n        foreach (var item in leftJoin)\n        {\n            foreach (var r in item.Right)\n                Console.WriteLine($\"Left: {item.Left}, Right: {r}\");\n        }\n    }\n}",
    hint: "DefaultIfEmpty provides a default value for empty sequences.",
