    question: "Use lambda with Reverse for reversing order.",
    mathSolution: "list.Reverse()",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers = { 1, 2, 3, 4, 5 };\n        \n        var reversed = numbers.Reverse();\n        Console.WriteLine($\"Reversed: {string.Join(\", \", reversed)}\");\n        \n        string word = \"hello\";\n        var reversedChars = word.Reverse();\n        Console.WriteLine($\"Reversed string: {new string(reversedChars.ToArray())}\");\n        \n        // In-place reverse for List<T>\n        List<int> list = new List<int> { 1, 2, 3, 4, 5 };\n        list.Reverse();\n        Console.WriteLine($\"In-place reverse: {string.Join(\", \", list)}\");\n        \n        // Reverse with custom logic using OrderByDescending\n        var reversedByOrder = numbers.OrderByDescending(x => x);\n        Console.WriteLine($\"OrderByDescending: {string.Join(\", \", reversedByOrder)}\");\n        \n        // Reverse a string using new string\n        string text = \"C# Programming\";\n        string reversedText = new string(text.Reverse().ToArray());\n        Console.WriteLine($\"Original: {text}\");\n        Console.WriteLine($\"Reversed: {reversedText}\");\n        \n        // Reverse a list of strings\n        List<string> fruits = new List<string> { \"Apple\", \"Banana\", \"Cherry\", \"Date\" };\n        var reversedFruits = fruits.AsEnumerable().Reverse();\n        Console.WriteLine($\"Reversed fruits: {string.Join(\", \", reversedFruits)}\");\n    }\n}",
    hint: "Reverse() returns reversed sequence; List.Reverse() modifies in place. For strings, use new string(reversedChars.ToArray()).",
